parameters.jsCode:
const webhook = $('Webhook Trigger').item.json.body;
const processData = $('Get Process').item.json.data;
const userData = $('Get User').item.json.data;
const conversations = $('Get Conversations').item.json.data || [];

const userName = userData.first_name || userData.username || 'Cliente';

const visaLabels = {
  'turismo': 'Turismo',
  'trabalho': 'Trabalho',
  'estudante': 'Estudante',
  'residencia': 'Residência',
  'transito': 'Trânsito'
};

const statusLabels = {
  'recebido': 'Recebido',
  'em_analise': 'Em Análise',
  'pendente_documentos': 'Pendente de Documentos',
  'aprovado': 'Aprovado',
  'rejeitado': 'Rejeitado',
  'finalizado': 'Finalizado',
  'cancelado': 'Cancelado'
};

const rawVisa = processData.visa_type || '';
const hasVisa = rawVisa && rawVisa !== 'a_definir';
const visaLabel = hasVisa ? (visaLabels[rawVisa] || rawVisa) : '';
const visaText = hasVisa ? ` de ${visaLabel}` : '';

const rawCountry = processData.destination_country || '';
const hasCountry = rawCountry && rawCountry.toLowerCase() !== 'a definir' && rawCountry !== 'a_definir';
const countryText = hasCountry ? ` para ${rawCountry}` : '';

const reason = webhook.reason || '';
const reasonText = reason ? ` Motivo: ${reason}.` : '';
const oldStatus = webhook.old_status;
const newStatus = webhook.new_status;
const newStatusLabel = statusLabels[newStatus] || newStatus;

const userConv = conversations.find(c => c.user_id === webhook.user_id);
const chatId = userConv ? userConv.chat_id : null;

const messages = {
  'recebido_em_analise': `Olá ${userName}! Seus documentos para o processo de visto${visaText}${countryText} foram recebidos e estão sendo analisados.`,
  'em_analise_pendente_documentos': `Olá ${userName}! Precisamos de documentos adicionais para seu processo de visto${visaText}${countryText}.${reasonText}`,
  'em_analise_aprovado': `Parabéns ${userName}! Seu visto${visaText}${countryText} foi aprovado!`,
  'em_analise_rejeitado': `Olá ${userName}. Seu processo de visto${visaText}${countryText} não foi aprovado. Recomendamos contato com nossa equipe.`,
  'aprovado_finalizado': `Olá ${userName}! Seu processo de visto${visaText}${countryText} foi finalizado com sucesso!`,
};

const key = `${oldStatus}_${newStatus}`;
let message = messages[key];

if (!message && newStatus === 'cancelado') {
  message = `Olá ${userName}. Seu processo de visto foi cancelado.${reasonText}`;
}

if (!message) {
  message = `Olá ${userName}! Seu processo de visto${visaText}${countryText} foi atualizado para: ${newStatusLabel}.`;
}

return [{ json: { chatId, message, userId: webhook.user_id, conversationId: userConv ? userConv._id : null } }];

